package net.postchain.rell.codegen.kotlin

import net.postchain.rell.codegen.document.AbstractDocument

class KotlinDocument(packageName: String, moduleName: String) : AbstractDocument(
    "// Generated by kotlin generator",
    formatePackage(packageName, moduleName)
) {
}

private fun formatePackage(packageName: String, moduleName: String) =
    if (moduleName.isBlank()) "package $packageName" else "package $packageName.$moduleName"